#include <bits/stdc++.h>
using namespace std;

using ll = long long;

const int MAXN = 1000005;

int n, q;
vector<int> g[MAXN];
vector<pair<int,int>> query[MAXN];   // {color, queryIndex}

int col[MAXN];
int sz[MAXN];
int id_map[MAXN];
ll ans[MAXN];

unordered_map<int,ll> tot[MAXN];  // subtree color frequencies
unordered_map<int,ll> topcnt;     // prefix color frequency

int FR;

/* ---------------- DSU on Tree DFS ---------------- */

void dfs(int u, int p) {
    sz[u] = 1;
    int mx = -1;
    int heavy = -1;

    for (int v : g[u]) {
        if (v == p) continue;
        dfs(v, u);
        sz[u] += sz[v];
        if (sz[v] > mx) {
            mx = sz[v];
            heavy = v;
        }
    }

    // leaf node
    if (heavy == -1) {
        id_map[u] = FR++;
        tot[id_map[u]][col[u]] = 1;

        for (auto &qu : query[u]) {
            ans[qu.second] = 0;
        }
        return;
    }

    // use heavy child's map
    id_map[u] = id_map[heavy];
    auto &heavyMap = tot[id_map[u]];

    unordered_map<int,ll> pairs;

    for (int v : g[u]) {
        if (v == p || v == heavy) continue;

        auto &smallMap = tot[id_map[v]];

        for (auto &x : smallMap) {
            int c = x.first;
            ll cnt = x.second;

            ll existing = heavyMap.count(c) ? heavyMap[c] : 0;
            pairs[c] += cnt * existing;
            heavyMap[c] += cnt;
        }

        smallMap.clear();
    }

    for (auto &qu : query[u]) {
        int color = qu.first;
        ans[qu.second] = 2LL * (pairs.count(color) ? pairs[color] : 0);
    }

    heavyMap[col[u]]++;
}

/* ---------------- Final DFS ---------------- */

void finalizeDFS(int u, int p) {
    for (auto &qu : query[u]) {
        ans[qu.second] *= (topcnt.count(qu.first) ? topcnt[qu.first] : 0);
    }

    topcnt[col[u]]++;

    for (int v : g[u]) {
        if (v == p) continue;
        finalizeDFS(v, u);
    }

    topcnt[col[u]]--;
}

/* ---------------- Main ---------------- */

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;

    while (t--) {
        cin >> n >> q;

        // clear previous test case
        for (int i = 0; i < n; i++) {
            g[i].clear();
            query[i].clear();
            tot[i].clear();
        }
        topcnt.clear();
        FR = 0;

        for (int i = 0; i < n; i++) {
            cin >> col[i];
        }

        for (int i = 0; i < n - 1; i++) {
            int u, v;
            cin >> u >> v;
            u--; v--;
            g[u].push_back(v);
            g[v].push_back(u);
        }

        for (int i = 0; i < q; i++) {
            int x, z;
            cin >> x >> z;
            x--;
            query[x].push_back({z, i});
        }

        dfs(0, -1);
        finalizeDFS(0, -1);

        for (int i = 0; i < q; i++) {
            cout << ans[i] << "\n";
        }
    }

    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

class Solution {

    int n, q;
    ArrayList<Integer>[] g;
    ArrayList<Query>[] query;

    int[] col;
    int[] sz;
    int[] id_map;
    long[] ans;

    HashMap<Integer, Long>[] tot;
    HashMap<Integer, Long> topcnt;

    int FR;

    static class Query {
        int color, index;
        Query(int c, int i) {
            color = c;
            index = i;
        }
    }

    void dfs(int u, int p) {
        sz[u] = 1;
        int mx = -1, heavy = -1;

        for (int v : g[u]) {
            if (v == p) continue;
            dfs(v, u);
            sz[u] += sz[v];
            if (sz[v] > mx) {
                mx = sz[v];
                heavy = v;
            }
        }

        if (heavy == -1) {
            id_map[u] = FR++;
            tot[id_map[u]].put(col[u], 1L);
            for (Query qu : query[u]) {
                ans[qu.index] = 0;
            }
            return;
        }

        id_map[u] = id_map[heavy];
        HashMap<Integer, Long> heavyMap = tot[id_map[u]];
        HashMap<Integer, Long> pairs = new HashMap<>();

        for (int v : g[u]) {
            if (v == p || v == heavy) continue;

            HashMap<Integer, Long> smallMap = tot[id_map[v]];

            for (Map.Entry<Integer, Long> entry : smallMap.entrySet()) {
                int c = entry.getKey();
                long cnt = entry.getValue();

                long existing = heavyMap.getOrDefault(c, 0L);
                pairs.put(c, pairs.getOrDefault(c, 0L) + cnt * existing);
                heavyMap.put(c, existing + cnt);
            }
            smallMap.clear();
        }

        for (Query qu : query[u]) {
            ans[qu.index] = 2L * pairs.getOrDefault(qu.color, 0L);
        }

        heavyMap.put(col[u], heavyMap.getOrDefault(col[u], 0L) + 1);
    }

    void finalizeDFS(int u, int p) {

        for (Query qu : query[u]) {
            ans[qu.index] *= topcnt.getOrDefault(qu.color, 0L);
        }

        topcnt.put(col[u], topcnt.getOrDefault(col[u], 0L) + 1);

        for (int v : g[u]) {
            if (v == p) continue;
            finalizeDFS(v, u);
        }

        topcnt.put(col[u], topcnt.get(col[u]) - 1);
    }

    long[] solve(int n, int q, int[] colors, int[][] edges, int[][] queriesInput) {

        this.n = n;
        this.q = q;

        g = new ArrayList[n];
        query = new ArrayList[n];
        col = colors;
        sz = new int[n];
        id_map = new int[n];
        ans = new long[q];
        tot = new HashMap[n];
        topcnt = new HashMap<>();
        FR = 0;

        for (int i = 0; i < n; i++) {
            g[i] = new ArrayList<>();
            query[i] = new ArrayList<>();
            tot[i] = new HashMap<>();
        }

        for (int[] e : edges) {
            int u = e[0];
            int v = e[1];
            g[u].add(v);
            g[v].add(u);
        }

        for (int i = 0; i < q; i++) {
            int x = queriesInput[i][0];
            int z = queriesInput[i][1];
            query[x].add(new Query(z, i));
        }

        dfs(0, -1);
        finalizeDFS(0, -1);

        return ans;
    }
}

public class Main {

    public static void main(String[] args) throws Exception {

        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder output = new StringBuilder();

        String firstLine = br.readLine();
        if (firstLine == null || firstLine.isEmpty()) return;

        int T = Integer.parseInt(firstLine.trim());

        while (T-- > 0) {

            StringTokenizer st = new StringTokenizer(br.readLine());
            int n = Integer.parseInt(st.nextToken());
            int q = Integer.parseInt(st.nextToken());

            int[] colors = new int[n];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < n; i++) {
                colors[i] = Integer.parseInt(st.nextToken());
            }

            int[][] edges = new int[n - 1][2];
            for (int i = 0; i < n - 1; i++) {
                st = new StringTokenizer(br.readLine());
                edges[i][0] = Integer.parseInt(st.nextToken()) - 1;
                edges[i][1] = Integer.parseInt(st.nextToken()) - 1;
            }

            int[][] queries = new int[q][2];
            for (int i = 0; i < q; i++) {
                st = new StringTokenizer(br.readLine());
                queries[i][0] = Integer.parseInt(st.nextToken()) - 1;
                queries[i][1] = Integer.parseInt(st.nextToken());
            }

            Solution sol = new Solution();
            long[] result = sol.solve(n, q, colors, edges, queries);

            for (long val : result) {
                output.append(val).append('\n');
            }
        }

        System.out.print(output.toString());
    }
}
